// Verify /api/wind-alert returns 400 when lat/lon are missing — caught by route schema validation.
async function testWindAlertMissingParams() {
  const res = await fetch('http://localhost:3001/api/wind-alert');
  assertEquals(res.status, 400, 'Missing params should return 400');
  const body = await res.json();
  // Route schema validation returns this shape
  assertEquals(body.error, 'Validation failed', 'Should report a schema validation failure');
  assert(body.details.length > 0, 'Should include validation detail messages');
}
